  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 52 ORDER BY created_at DESC LIMIT 1), 'listening', 20, '여자 :이번 정규 앨범의 곡들 중 악기 없이 목소리만으로 노래한 곡들이
